package com.example.userservice.service;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClient;

import java.util.Collections;
import java.util.Map;

@Service
public class ExternalApiService {

    private final RestClient restClient;

    @Value(\""'${external.api.base-url:https://api.example.com}")
    private String baseUrl;

    public ExternalApiService() {
        this.restClient = RestClient.create();
    }

    public boolean verifyEmail(String email) {
        try {
            String url = baseUrl + "/verify/email?email=" + email;
            Map response = restClient.get()
                    .uri(url)
                    .retrieve()
                    .body(Map.class);
            if (response != null) {
                Object valid = response.get("valid");
                return Boolean.TRUE.equals(valid);
            }
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    public void sendNotification(String userId, String message) {
        try {
            String url = baseUrl + "/notifications";

            Map<String, String> payload = Map.of(
                "userId", userId,
                "message", message,
                "type", "USER_UPDATE"
            );

            restClient.post()
                    .uri(url)
                    .contentType(MediaType.APPLICATION_JSON)
                    .accept(MediaType.APPLICATION_JSON)
                    .body(payload)
                    .retrieve()
                    .toBodilessEntity();
        } catch (Exception e) {
            System.err.println("Failed to send notification: " + e.getMessage());
        }
    }

    @SuppressWarnings("unchecked")
    public Map<String, Object> enrichUserProfile(String userId) {
        try {
            String url = baseUrl + "/users/" + userId + "/profile";

            Map response = restClient.get()
                    .uri(url)
                    .accept(MediaType.APPLICATION_JSON)
                    .retrieve()
                    .body(Map.class);

            return response != null ? response : Collections.emptyMap();
        } catch (Exception e) {
            return Collections.emptyMap();
        }
    }

    public boolean requestDataDeletion(String userId) {
        try {
            String url = baseUrl + "/users/" + userId + "/data";
            restClient.delete()
                    .uri(url)
                    .retrieve()
                    .toBodilessEntity();
            return true;
        } catch (Exception e) {
            return false;
        }
    }
}
